SELECT COUNT(enrollment_id) AS number_of_students_enrolled
FROM student_classes
WHERE class_id = 1;

WITH TopGrades AS (
    SELECT grade
    FROM (
        SELECT grade, ROW_NUMBER() OVER (PARTITION BY class_id ORDER BY grade DESC) AS rn
        FROM student_classes
    ) AS ranked_grades
    WHERE rn = 1
)
SELECT MAX(grade) AS highest_grade
FROM TopGrades;
